      "Wa-you-'adh-dhi-bal-mou-naa-fi-qee-na-wal-mou-naa-fi-qaa-ti-wal-moush-ri-kee-na-wal-moush-ri-kaa-tiz-dha-an-noo-bil-laa-hi-dhan-nas-saw-'i-'a-LAY-him-daa-'i-ra-tous-saw-'i-wa-gha-di-bal-laa-hou-'a-LAY-him-wa-la-'a-na-houm-wa-a-'ad-da-la-houm-ja-han-na-ma-wa-saa-'at-ma-SEE-RAA",
      "Wa-lil-laa-hi-jou-noo-dus-sa-maa-waa-ti-wal-ardi-wa-kaa-nal-laa-hou-'a-zee-zan-ha-KEE-MAA",
      "In-naa-ar-sal-naa-ka-shaa-hi-dan-wa-mou-bash-shi-ran-wa-na-dhee-RAA",
      "Li-tou'-mi-noo-bil-laa-hi-wa-ra-soo-li-hi-wa-tou-'az-zi-roo-hou-wa-tou-waq-qi-roo-hou-wa-tou-sab-bi-hoo-hou-bouk-ra-tan-wa-a-SEE-LAA",
      "In-nal-la-dhee-na-you-baa-yi-'oo-na-ka-in-na-maa-you-baa-yi-'oo-nal-laa-ha-ya-dol-laa-hi-faw-qa-ay-dee-him-fa-man-na-ka-tha-fa-in-na-maa-yan-ko-thou-'a-laa-nafs-hi-hi-wa-man-aw-faa-bi-maa-'aa-ha-da-'a-LAY-hol-laa-ha-fa-sa-you'-tee-hi-aj-ran-'a-ZEE-MAA",
      "Sa-ya-qoo-lou-la-ka-al-moukh-al-la-foo-na-mi-nal-a'-raa-bi-sha-gha-la-naa-am-waa-lou-naa-wa-ah-lou-naa-fas-ta-ghfir-la-naa-ya-qoo-loo-na-bi-al-si-na-ti-him-maa-lay-sa-fee-qou-loo-bi-him-qoul-fa-man-yam-li-kou-la-KOM-mi-nal-laa-hi-shay-'an-in-a-raa-da-bi-KOM-dar-ran-aw-a-raa-da-bi-KOM-naf-'an-bal-kaa-nal-laa-hou-bi-maa-ta'-ma-loo-na-kha-BEE-RAA",
      "Bal-dha-nan-toom-an-lan-yan-qa-li-bar-ra-soo-lou-wal-mou'-mi-noo-na-i-laa-ah-lee-him-a-ba-dan-wa-zouy-yi-na-dhaa-li-ka-fee-qou-loo-bi-KOM-wa-dha-nan-toom-dhan-nas-saw-'i-wa-koun-toom-qaw-man-BOO-RAA",
      "Wa-man-lam-you'-min-bil-laa-hi-wa-ra-soo-li-hi-fa-in-naa-a'-tad-naa-lil-kaa-fi-ree-na-sa-'EE-RAA",
      "Wa-lil-laa-hi-moul-kou-sam-maa-waa-ti-wal-ardi-yagh-fi-rou-li-man-ya-shaa-'ou-wa-you-'adh-dhi-bou-man-ya-shaa-'ou-wa-kaa-nal-laa-hou-ghaf-foor-an-ra-HEE-MAA",
      "Sa-ya-qoo-loul-moukh-al-la-foo-na-i-dhaan-ta-laq-toom-i-laa-magh-aa-ni-ma-li-ta'-khou-dhoo-haa-dha-roo-naa-nat-ta-bi'-KOM-you-ree-doo-na-an-you-bad-di-loo-ka-laa-mal-laa-hi-qoul-lan-tat-ta-bi-'oo-naa-ka-dhaa-li-KOM-qaa-lal-laa-hou-min-qa-bou-fa-sa-ya-qoo-loo-na-bal-ta-hsou-doo-na-naa-bal-kaa-noo-laa-yaf-qa-hoo-na-il-laa-qa-LEE-LAA",
