      "Al-la-dhee-na-yab-kha-loo-na-wa-ya'-mou-roo-nan-naa-sa-bil-boukh-li-wa-man-ya-ta-wal-la-fa-in-nal-laa-ha-hou-wal-gha-ni-youl-ha-MEED",
