      "Fa-aa-mi-noo-bil-laa-hi-wa-ra-soo-li-hi-wan-noo-ril-la-dhee-an-zal-naa-wal-laa-hou-bi-maa-ta'-ma-loo-na-kha-BEER",
      "Yaw-ma-yaj-ma-'ou-KOM-li-yaw-mil-jam-'i-dhaa-li-ka-yaw-mut-ta-ghaa-bou-ni-wa-man-you'-min-bil-laa-hi-wa-ya'-mal-saa-li-han-you-kaf-fir-'an-hou-say-yi-aa-ti-hi-wa-youd-khi-hou-jan-naa-tin-taj-ree-min-tah-ti-haal-an-haa-rou-khaa-li-dee-na-fee-haa-a-ba-daan-dhaa-li-kal-faw-zoul-'a-DHEEM",
      "Wal-la-dhee-na-ka-fa-roo-wa-kadh-dha-boo-bi-aa-yaa-ti-naa-ou-laa-'i-ka-as-haa-boun-naar-khaa-li-dee-na-fee-haa-wa-bi'-sal-ma-SEER",
